#include <bits/stdc++.h>
using namespace std;

const int N=4e6+10;

int n,m,k,now,p[N];
int head[N],ver[2*N],nxt[2*N],tot;
int dfn[N],low[N],num,stk[N],top,c[N],cnt;
bool ins[N];

void add(int x,int y){
    ver[++tot]=y,nxt[tot]=head[x],head[x]=tot;
}

void tarjan(int x){
    dfn[x]=low[x]=++num;
    stk[++top]=x,ins[x]=1;
    for(int i=head[x],y;i;i=nxt[i])
        if(!dfn[y=ver[i]]){
            tarjan(y);
            low[x]=min(low[x],low[y]);
        }else if(ins[y])
            low[x]=min(low[x],dfn[y]);
    if(dfn[x]==low[x]){
        cnt++;
        int z;
        do{
            z=stk[top--],ins[z]=0,c[z]=cnt;
        }while(z!=x);
    }
}

int main(){
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1,u,v;i<=m;i++){
        scanf("%d%d",&u,&v);
        add(u,v+n);
        add(v,u+n);
    }
    now=2*n;
    for(int i=1,w,lst;i<=k;i++){
        scanf("%d",&w);
        for(int j=1;j<=w;j++)
            scanf("%d",&p[j]);
        lst=0;
        for(int j=1;j<=w;j++){
            if(lst) add(p[j]+n,lst);
            now++;
            if(lst) add(now,lst);
            add(now,p[j]);
            lst=now;
        }
        lst=0;
        for(int j=w;j;j--){
            if(lst) add(p[j]+n,lst);
            now++;
            if(lst) add(now,lst);
            add(now,p[j]);
            lst=now;
        }
    }
    for(int i=1;i<=now;i++)
        if(!dfn[i])
            tarjan(i);
    bool flag=true;
    for(int i=1;i<=n;i++)
        if(c[i]==c[i+n]){
            flag=false;
            break;
        }
    if(flag)
        puts("TAK");
    else
        puts("NIE");
    return 0;
}
